{"content":"import json
from typing import Optional

from sqlalchemy.orm import Session

from app.models import RuleVersion, QuotaDetail, QuotaBatch


class RuleEngine:
    def __init__(self, db: Session):
        self.db = db
        self._active_rule: Optional[RuleVersion] = None

    @property
    def active_rule(self) -> RuleVersion:
        if self._active_rule is None:
            rule = (
                self.db.query(RuleVersion)
                .filter(RuleVersion.is_active == 1)
                .order_by(RuleVersion.created_at.desc())
                .first()
            )
            if rule is None:
                rule = self._ensure_default_rule()
            self._active_rule = rule
        return self._active_rule

    def _ensure_default_rule(self) -> RuleVersion:
        rule = RuleVersion(
            version="v1.0.0",
            description="默认规则版本",
            max_quota_overage_pct=0.2,
            locked_tenant_patterns=json.dumps(["LOCKED_*"]),
            requires_supplement_types=json.dumps(["storage", "api_calls"]),
            conflict_detection_enabled=1,
            is_active=1,
        )
        self.db.add(rule)
        self.db.flush()
        return rule

    @property
    def current_version(self) -> str:
        return self.active_rule.version

    def is_tenant_locked(self, tenant_id: str) -> bool:
        patterns = json.loads(self.active_rule.locked_tenant_patterns)
        for pattern in patterns:
            if pattern.endswith("*"):
                if tenant_id.startswith(pattern[:-1]):
                    return True
            elif tenant_id == pattern:
                return True
        return False

    def needs_supplement(self, quota_type: str) -> bool:
        types = json.loads(self.active_rule.requires_supplement_types)
        return quota_type in types

    def check_overage(self, current: float, requested: float) -> bool:
        if current <= 0:
            return False
        overage = (requested - current) / current
        return overage > self.active_rule.max_quota_overage_pct

    def detect_conflict(
        self, batch_id: str, tenant_id: str, quota_type: str, quota_key: str
    ) -> Optional[str]:
        if not self.active_rule.conflict_detection_enabled:
            return None
        existing = (
            self.db.query(QuotaDetail)
            .filter(
                QuotaDetail.batch_id != batch_id,
                QuotaDetail.tenant_id == tenant_id,
                QuotaDetail.quota_type == quota_type,
                QuotaDetail.quota_key == quota_key,
                QuotaDetail.disposition.in_(["processable", "needs_supplement"]),
            )
            .first()
        )
        if existing:
            return (
                f"租户{tenant_id}的{quota_type}/{quota_key}在批次"
                f"{existing.batch_id}中已有生效记录"
            )
        return None

    def evaluate_detail(
        self,
        batch_id: str,
        tenant_id: str,
        quota_type: str,
        quota_key: str,
        requested_value: float,
        current_value: float,
    ) -> dict:
        if self.is_tenant_locked(tenant_id):
            return {
                "disposition": "locked",
                "risk_label": "high_risk",
                "failure_reason": f"租户{tenant_id}处于锁定状态",
            }

        conflict = self.detect_conflict(batch_id, tenant_id, quota_type, quota_key)
        if conflict:
            return {
                "disposition": "failed",
                "risk_label": "conflict",
                "failure_reason": conflict,
            }

        if self.needs_supplement(quota_type):
            return {
                "disposition": "needs_supplement",
                "risk_label": "warning",
                "failure_reason": None,
            }

        if self.check_overage(current_value, requested_value):
            return {
                "disposition": "needs_supplement",
                "risk_label": "warning",
                "failure_reason": (
                    f"申请值{requested_value}超出当前值{current_value}"
                    f"的{self.active_rule.max_quota_overage_pct * 100}%以上"
                ),
            }

        return {
            "disposition": "processable",
            "risk_label": "normal",
            "failure_reason": None,
        }
